export enum Severity {
  OPERATIONAL = 'OPERATIONAL',
  DEGRADED = 'DEGRADED',
  OUTAGE = 'OUTAGE'
}

export interface RemoteDashboardConfig {
  id: string;
  name: string;
  url: string;
  adminSecret: string;
  color?: string;
}

export interface Region { id: string; name: string; }
export interface Component { id: string; regionId: string; name: string; description: string; sla90?: number; createdAt?: string; }
export interface Template { id: string; componentName: string; name: string; title: string; description: string; }
export interface Incident { id: string; componentId: string; title: string; description: string; severity: Severity; startTime: string; endTime: string | null; }
export interface Subscription { id: string; email: string; createdAt: string; }
export interface NotificationSettings { incidentNewTemplate: string; incidentResolvedTemplate: string; }
export interface AdminUser { id: string; username: string; createdAt: string; }
export interface AuditLog { id: string; username: string; actionType: string; targetType: string; targetName: string; details: any; createdAt: string; }

export interface AppState {
  // Remote Context
  dashboards: RemoteDashboardConfig[];
  activeDashboardId: string | null;

  // Data for the active dashboard
  regions: Region[];
  components: Component[];
  templates: Template[];
  incidents: Incident[];
  subscriptions: Subscription[];
  notificationSettings: NotificationSettings;
  users: AdminUser[];
  auditLogs: AuditLog[];

  isAuthenticated: boolean;
  currentUser?: string;
  timezoneOffset: number;
}

-- Enable UUID extension
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

-- Migration: Detect and fix old tables
DROP TABLE IF EXISTS incidents CASCADE;
DROP TABLE IF EXISTS components CASCADE;
DROP TABLE IF EXISTS services CASCADE;
DROP TABLE IF EXISTS templates CASCADE;
DROP TABLE IF EXISTS regions CASCADE;

-- Users table
CREATE TABLE IF NOT EXISTS users (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    username TEXT UNIQUE NOT NULL,
    password_hash TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Regions table
CREATE TABLE IF NOT EXISTS regions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Components table
CREATE TABLE IF NOT EXISTS components (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    region_id UUID REFERENCES regions(id) ON DELETE CASCADE,
    name TEXT NOT NULL,
    description TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Templates table
CREATE TABLE IF NOT EXISTS templates (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    component_name TEXT NOT NULL,
    name TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Incidents table
CREATE TABLE IF NOT EXISTS incidents (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    component_id UUID REFERENCES components(id) ON DELETE CASCADE,
    title TEXT NOT NULL,
    description TEXT,
    severity TEXT NOT NULL,
    start_time TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    end_time TIMESTAMP WITH TIME ZONE
);

-- Subscriptions table
CREATE TABLE IF NOT EXISTS subscriptions (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    email TEXT UNIQUE NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Notification settings table
CREATE TABLE IF NOT EXISTS notification_settings (
    key TEXT PRIMARY KEY,
    value TEXT NOT NULL
);

-- Audit logs table
CREATE TABLE IF NOT EXISTS audit_logs (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    username TEXT NOT NULL,
    action_type TEXT NOT NULL,
    target_type TEXT NOT NULL,
    target_name TEXT,
    details JSONB,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

-- Default templates
INSERT INTO notification_settings (key, value) VALUES 
('incident_new_template', 'New Incident: {title} affecting {component} in {region}. Severity: {severity}. Visit status page for details.'),
('incident_resolved_template', 'Resolved: The issue with {component} ({title}) has been resolved. Service is back to operational.')
ON CONFLICT (key) DO NOTHING;

-- Indexes
CREATE INDEX IF NOT EXISTS idx_components_region ON components(region_id);
CREATE INDEX IF NOT EXISTS idx_templates_component_name ON templates(component_name);
CREATE INDEX IF NOT EXISTS idx_incidents_component ON incidents(component_id);
CREATE INDEX IF NOT EXISTS idx_incidents_active ON incidents(end_time) WHERE end_time IS NULL;
CREATE INDEX IF NOT EXISTS idx_audit_logs_created ON audit_logs(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_subscriptions_email ON subscriptions(email);

import React, { createContext, useContext, useState, useEffect, useCallback, useMemo } from 'react';
import { AppState, Severity, NotificationSettings, RemoteDashboardConfig } from './types.ts';
import { portalApi, createRemoteApi, nodeApi } from './services/api.ts';

interface AppContextType {
  state: AppState;
  isLoading: boolean;
  switchDashboard: (id: string) => void;
  // Admin Data Management
  fetchAdminData: () => Promise<void>;
  getSubscribers: (page?: number, limit?: number, search?: string) => Promise<any>;
  // All actions below proxy to the ACTIVE remote dashboard
  addRegion: (name: string) => Promise<void>;
  removeRegion: (id: string) => Promise<void>;
  addComponent: (regionId: string, name: string, description: string) => Promise<void>;
  removeComponent: (id: string) => Promise<void>;
  addTemplate: (template: any) => Promise<void>;
  updateTemplate: (id: string, template: any) => Promise<void>;
  removeTemplate: (id: string) => Promise<void>;
  reportIncident: (incident: any) => Promise<void>;
  updateIncident: (id: string, incident: any) => Promise<void>;
  resolveIncident: (incidentId: string) => Promise<void>;
  addSubscriber: (email: string) => Promise<void>;
  updateSubscriber: (id: string, email: string) => Promise<void>;
  removeSubscriber: (id: string) => Promise<void>;
  saveNotificationSettings: (settings: NotificationSettings) => Promise<void>;
  login: (credentials: any) => Promise<void>;
  logout: () => void;
  calculateSLA: (componentId: string, days?: number) => number;
  setTimezoneOffset: (offset: number) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const TOKEN_KEY = 'voximplant_portal_token';
const USER_KEY = 'voximplant_portal_user';

const IS_HUB_MODE = (process.env as any).IS_HUB === true;

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AppState>({
    dashboards: [],
    activeDashboardId: null,
    regions: [],
    components: [],
    templates: [],
    incidents: [],
    subscriptions: [],
    notificationSettings: { incidentNewTemplate: '', incidentResolvedTemplate: '' },
    users: [],
    auditLogs: [],
    isAuthenticated: !!localStorage.getItem(TOKEN_KEY),
    currentUser: localStorage.getItem(USER_KEY) || undefined,
    timezoneOffset: (new Date().getTimezoneOffset() * -1),
  });
  const [isLoading, setIsLoading] = useState(true);

  const activeDashboard = useMemo(() => 
    state.dashboards.find(d => d.id === state.activeDashboardId), 
    [state.dashboards, state.activeDashboardId]
  );

  const remoteApi = useMemo(() => {
    if (IS_HUB_MODE) {
      return activeDashboard ? createRemoteApi(activeDashboard) : null;
    }
    return nodeApi;
  }, [activeDashboard]);

  const fetchData = useCallback(async () => {
    try {
      if (IS_HUB_MODE) {
        if (!remoteApi || !activeDashboard) return;

        setState(prev => ({
          ...prev,
          regions: [],
          components: [],
          templates: [],
          incidents: [],
          auditLogs: [],
          subscriptions: []
        }));

        const [status, admin] = await Promise.all([
          (remoteApi as any).getStatus().catch((e: any) => { console.error("Status fetch failed", e); return {}; }),
          (remoteApi as any).getAdminData().catch((e: any) => { console.error("Admin data fetch failed", e); return {}; })
        ]);

        setState(prev => ({ ...prev, ...status, ...admin }));
      } else {
        const status = await nodeApi.getStatus();
        setState(prev => ({ ...prev, ...status }));
      }
    } catch (err) {
      console.error("Critical error in fetchData", err);
    }
  }, [remoteApi, activeDashboard]);

  useEffect(() => {
    const init = async () => {
      setIsLoading(true);
      if (IS_HUB_MODE) {
        if (state.isAuthenticated) {
          try {
            const configs = await portalApi.getDashboardConfigs();
            setState(prev => {
              const activeId = prev.activeDashboardId || (configs.length > 0 ? configs[0].id : null);
              return { ...prev, dashboards: configs, activeDashboardId: activeId };
            });
          } catch (err) {
            console.error("Auth initialization failed", err);
            logout();
          } finally {
            setIsLoading(false);
          }
        } else {
          setIsLoading(false);
        }
      } else {
        await fetchData();
        setIsLoading(false);
      }
    };
    init();
  }, [state.isAuthenticated]);

  useEffect(() => {
    if (IS_HUB_MODE && state.activeDashboardId) {
      fetchData();
    }
  }, [state.activeDashboardId, fetchData]);

  const wrapAction = async (action: () => Promise<any>) => {
    try {
      await action();
      await fetchData();
    } catch (err) {
      console.error("Action Execution Failed:", err);
      throw err;
    }
  };

  const switchDashboard = (id: string) => setState(prev => ({ ...prev, activeDashboardId: id }));

  const logout = () => {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(USER_KEY);
    setState(prev => ({ ...prev, isAuthenticated: false, currentUser: undefined }));
  };

  const login = async (cred: any) => {
    const { token, username } = await portalApi.login(cred);
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(USER_KEY, username);
    setState(prev => ({ ...prev, isAuthenticated: true, currentUser: username }));
  };

  const setTimezoneOffset = (offset: number) => setState(prev => ({ ...prev, timezoneOffset: offset }));

  const calculateSLA = useCallback((componentId: string, days = 90) => {
    const now = Date.now();
    const periodStart = now - (days * 24 * 60 * 60 * 1000);
    const totalMinutes = days * 24 * 60;
    const componentIncidents = state.incidents.filter(i => i.componentId === componentId);
    let totalDowntimeMinutes = 0;
    componentIncidents.forEach(inc => {
      const start = new Date(inc.startTime).getTime();
      const end = inc.endTime ? new Date(inc.endTime).getTime() : now;
      const incStart = Math.max(start, periodStart);
      const incEnd = Math.min(end, now);
      if (incEnd > incStart) {
        const impactFactor = inc.severity === Severity.OUTAGE ? 1 : 0.5;
        totalDowntimeMinutes += ((incEnd - incStart) / 60000) * impactFactor;
      }
    });
    return Math.max(0, Math.min(100, parseFloat(((totalMinutes - totalDowntimeMinutes) / totalMinutes * 100).toFixed(3))));
  }, [state.incidents]);

  return (
    <AppContext.Provider value={{
      state, isLoading, switchDashboard,
      fetchAdminData: fetchData,
      getSubscribers: (p, l, s) => (remoteApi as any).getSubscribers(p, l, s),
      addRegion: (n) => wrapAction(() => (remoteApi as any).createRegion(n)),
      removeRegion: (id) => wrapAction(() => (remoteApi as any).deleteRegion(id)),
      addComponent: (rid, n, d) => wrapAction(() => (remoteApi as any).createComponent(rid, n, d)),
      removeComponent: (id) => wrapAction(() => (remoteApi as any).deleteComponent(id)),
      addTemplate: (t) => wrapAction(() => (remoteApi as any).createTemplate(t)),
      updateTemplate: (id, t) => wrapAction(() => (remoteApi as any).updateTemplate(id, t)),
      removeTemplate: (id) => wrapAction(() => (remoteApi as any).deleteTemplate(id)),
      reportIncident: (inc) => wrapAction(() => (remoteApi as any).createIncident(inc)),
      updateIncident: (id, inc) => wrapAction(() => (remoteApi as any).updateIncident(id, inc)),
      resolveIncident: (id) => wrapAction(() => (remoteApi as any).resolveIncident(id)),
      addSubscriber: (e) => wrapAction(() => remoteApi!.createSubscriber(e)),
      updateSubscriber: (id, e) => wrapAction(() => (remoteApi as any).createSubscriber(e)),
      removeSubscriber: (idOrEmail) => wrapAction(() => remoteApi!.deleteSubscriber(idOrEmail)),
      saveNotificationSettings: (s) => wrapAction(() => (remoteApi as any).updateNotificationSettings(s)),
      login, logout, setTimezoneOffset, calculateSLA
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import 'dotenv/config';
import express from 'express';
import cookieParser from 'cookie-parser';
import path from 'path';
import fs from 'fs';
import * as esbuild from 'esbuild';
import crypto from 'crypto';

// Import Node-specific services
import pool from './lib/db.js';
import { incidentService } from './services/incidentService.js';
import { auditService } from './services/auditService.js';

const app = express();
const rootPath = path.resolve();
const MODE = process.env.MODE || 'NODE';
const IS_HUB = MODE === 'HUB';

app.use((req, res, next) => {
  const origin = req.headers.origin;
  res.header('Access-Control-Allow-Origin', origin || '*');
  res.header('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, OPTIONS');
  res.header('Access-Control-Allow-Headers', 'Content-Type, X-ADMIN-SECRET, Authorization, X-Requested-With');
  res.header('Access-Control-Allow-Credentials', 'true');
  res.header('Access-Control-Max-Age', '86400');
  if (req.method === 'OPTIONS') return res.status(204).send();
  next();
});

app.use(express.json());
app.use(cookieParser());

app.use(async (req, res, next) => {
  const cleanPath = req.path.split('?')[0];
  if (cleanPath.endsWith('.ts') || cleanPath.endsWith('.tsx')) {
    const filePath = path.join(rootPath, cleanPath.startsWith('/') ? cleanPath.substring(1) : cleanPath);
    if (!fs.existsSync(filePath)) return next();
    try {
      const content = fs.readFileSync(filePath, 'utf8');
      const result = await esbuild.transform(content, {
        loader: cleanPath.endsWith('.tsx') ? 'tsx' : 'ts',
        format: 'esm',
        target: 'es2020',
        sourcemap: 'inline',
        define: { 
          'process.env.API_KEY': JSON.stringify(process.env.API_KEY || ''),
          'process.env.IS_HUB': JSON.stringify(IS_HUB)
        }
      });
      res.type('application/javascript').send(result.code);
    } catch (err) {
      res.status(500).send(`console.error("Transpilation failed");`);
    }
  } else next();
});

if (!IS_HUB) {
  const nodeAuth = (req, res, next) => {
    const secret = req.headers['x-admin-secret'];
    if (secret !== process.env.ADMIN_SECRET) return res.status(401).json({ error: 'Unauthorized' });
    req.user = 'remote-admin'; 
    next();
  };

  app.get('/api/status', async (req, res) => {
    try {
      const regions = await pool.query('SELECT id, name FROM regions');
      const components = await pool.query('SELECT id, region_id as "regionId", name, description, created_at as "createdAt" FROM components');
      const incidents = await pool.query('SELECT id, component_id as "componentId", title, description, severity, start_time as "startTime", end_time as "endTime" FROM incidents ORDER BY start_time DESC');
      res.json({ regions: regions.rows, components: components.rows, incidents: incidents.rows });
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  });

  app.get('/api/admin/data', nodeAuth, async (req, res) => {
    try {
      const templates = await pool.query('SELECT id, component_name as "componentName", name, title, description FROM templates');
      const auditLogs = await pool.query('SELECT id, username, action_type as "actionType", target_type as "targetType", target_name as "targetName", details, created_at as "createdAt" FROM audit_logs ORDER BY created_at DESC LIMIT 50');
      const settingsRows = await pool.query('SELECT key, value FROM notification_settings');
      const notificationSettings = {
        incidentNewTemplate: settingsRows.rows.find(r => r.key === 'incident_new_template')?.value || '',
        incidentResolvedTemplate: settingsRows.rows.find(r => r.key === 'incident_resolved_template')?.value || ''
      };
      res.json({ templates: templates.rows, auditLogs: auditLogs.rows, notificationSettings });
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  });

  app.get('/api/admin/subscribers', nodeAuth, async (req, res) => {
    const page = parseInt(req.query.page) || 1;
    const limit = parseInt(req.query.limit) || 10;
    const offset = (page - 1) * limit;
    const search = req.query.search ? `%${req.query.search}%` : '%';
    try {
      const countRes = await pool.query('SELECT count(*) FROM subscriptions WHERE email LIKE $1', [search]);
      const itemsRes = await pool.query('SELECT id, email, created_at as "createdAt" FROM subscriptions WHERE email LIKE $1 ORDER BY created_at DESC LIMIT $2 OFFSET $3', [search, limit, offset]);
      res.json({ total: parseInt(countRes.rows[0].count), items: itemsRes.rows });
    } catch (err) {
      res.status(500).json({ error: err.message });
    }
  });

  app.post('/api/admin/incidents', nodeAuth, async (req, res) => {
    try {
      const incident = await incidentService.createIncident(req.user, req.body);
      res.json(incident);
    } catch (err) { res.status(500).json({ error: err.message }); }
  });

  app.put('/api/admin/incidents/:id', nodeAuth, async (req, res) => {
    try {
      const incident = await incidentService.updateIncident(req.user, req.params.id, req.body);
      res.json(incident);
    } catch (err) { res.status(500).json({ error: err.message }); }
  });

  app.post('/api/admin/regions', nodeAuth, async (req, res) => {
    const result = await pool.query('INSERT INTO regions (name) VALUES ($1) RETURNING id, name', [req.body.name]);
    await auditService.log(req.user, 'CREATE_REGION', 'REGION', req.body.name);
    res.json(result.rows[0]);
  });

  app.delete('/api/admin/regions/:id', nodeAuth, async (req, res) => {
    const region = await pool.query('SELECT name FROM regions WHERE id = $1', [req.params.id]);
    await pool.query('DELETE FROM regions WHERE id = $1', [req.params.id]);
    await auditService.log(req.user, 'DELETE_REGION', 'REGION', region.rows[0]?.name);
    res.json({ success: true });
  });

  app.post('/api/admin/components', nodeAuth, async (req, res) => {
    const { regionId, name, description } = req.body;
    const result = await pool.query('INSERT INTO components (region_id, name, description) VALUES ($1, $2, $3) RETURNING id, region_id as "regionId", name, description', [regionId, name, description]);
    await auditService.log(req.user, 'CREATE_COMPONENT', 'COMPONENT', name);
    res.json(result.rows[0]);
  });

  app.delete('/api/admin/components/:id', nodeAuth, async (req, res) => {
    const comp = await pool.query('SELECT name FROM components WHERE id = $1', [req.params.id]);
    await pool.query('DELETE FROM components WHERE id = $1', [req.params.id]);
    await auditService.log(req.user, 'DELETE_COMPONENT', 'COMPONENT', comp.rows[0]?.name);
    res.json({ success: true });
  });

  app.post('/api/admin/subscriptions', async (req, res) => {
    try {
      const result = await pool.query('INSERT INTO subscriptions (email) VALUES ($1) ON CONFLICT (email) DO UPDATE SET email = EXCLUDED.email RETURNING id, email, created_at as "createdAt"', [req.body.email]);
      res.json(result.rows[0]);
    } catch (err) { res.status(500).json({ error: err.message }); }
  });

  app.delete('/api/admin/subscriptions/by-email', async (req, res) => {
    try {
      await pool.query('DELETE FROM subscriptions WHERE email = $1', [req.body.email]);
      res.json({ success: true });
    } catch (err) { res.status(500).json({ error: err.message }); }
  });

  app.delete('/api/admin/subscriptions/:id', nodeAuth, async (req, res) => {
    await pool.query('DELETE FROM subscriptions WHERE id = $1', [req.params.id]);
    res.json({ success: true });
  });

  app.post('/api/admin/notification-settings', nodeAuth, async (req, res) => {
    const { incidentNewTemplate, incidentResolvedTemplate } = req.body;
    await pool.query('INSERT INTO notification_settings (key, value) VALUES ($1, $2) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value', ['incident_new_template', incidentNewTemplate]);
    await pool.query('INSERT INTO notification_settings (key, value) VALUES ($1, $2) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value', ['incident_resolved_template', incidentResolvedTemplate]);
    res.json({ success: true });
  });

  app.post('/api/admin/templates', nodeAuth, async (req, res) => {
    const { componentName, name, title, description } = req.body;
    const resT = await pool.query('INSERT INTO templates (component_name, name, title, description) VALUES ($1, $2, $3, $4) RETURNING id, component_name as "componentName", name, title, description', [componentName, name, title, description]);
    res.json(resT.rows[0]);
  });

  app.put('/api/admin/templates/:id', nodeAuth, async (req, res) => {
    const { componentName, name, title, description } = req.body;
    const resT = await pool.query('UPDATE templates SET component_name=$1, name=$2, title=$3, description=$4 WHERE id=$5 RETURNING id, component_name as "componentName", name, title, description', [componentName, name, title, description, req.params.id]);
    res.json(resT.rows[0]);
  });

  app.delete('/api/admin/templates/:id', nodeAuth, async (req, res) => {
    await pool.query('DELETE FROM templates WHERE id = $1', [req.params.id]);
    res.json({ success: true });
  });
}

if (IS_HUB) {
  const portalSessions = new Map();
  let DASHBOARD_CONFIGS = [];
  try { DASHBOARD_CONFIGS = JSON.parse(process.env.DASHBOARDS || '[]'); } catch (e) {}

  const authenticatePortal = (req, res, next) => {
    const token = req.cookies.session_id || req.headers.authorization?.split(' ')[1];
    if (!portalSessions.has(token)) return res.status(401).json({ error: 'Unauthorized' });
    next();
  };

  app.post('/api/portal/auth', (req, res) => {
    const { username, password } = req.body;
    if (username === process.env.ADMIN_USER && username && password === process.env.ADMIN_PASS) {
      const token = crypto.randomBytes(32).toString('hex');
      portalSessions.set(token, username);
      res.cookie('session_id', token, { httpOnly: true });
      res.json({ token, username });
    } else res.status(401).json({ error: 'Invalid Credentials' });
  });

  app.get('/api/portal/configs', authenticatePortal, (req, res) => res.json(DASHBOARD_CONFIGS));
}

app.use(express.static(rootPath));
app.get('*', (req, res) => res.sendFile(path.join(rootPath, 'index.html')));
const port = parseInt(process.env.PORT || '3000');
app.listen(port, () => console.log(`[SERVICE] Running on port ${port}`));

import { RemoteDashboardConfig } from '../types.ts';

const TOKEN_KEY = 'voximplant_portal_token';

const handleResponse = async (res: Response, url: string) => {
  if (!res.ok) {
    const errorData = await res.json().catch(() => ({}));
    throw new Error(errorData.error || `HTTP error! status: ${res.status}`);
  }
  return res.json();
};

export const nodeApi = {
  async getStatus() {
    const url = `/api/status`;
    const res = await fetch(url);
    return handleResponse(res, url);
  },
  async createSubscriber(email: string) {
    const url = `/api/admin/subscriptions`;
    const res = await fetch(url, { 
      method: 'POST', 
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email }) 
    });
    return handleResponse(res, url);
  },
  async deleteSubscriber(email: string) {
    const url = `/api/admin/subscriptions/by-email`;
    const res = await fetch(url, { 
      method: 'DELETE', 
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email }) 
    });
    return handleResponse(res, url);
  }
};

export const createRemoteApi = (config: RemoteDashboardConfig) => {
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
    'X-ADMIN-SECRET': config.adminSecret,
  };
  const base = config.url.endsWith('/') ? config.url.slice(0, -1) : config.url;

  return {
    async getStatus() {
      const url = `${base}/api/status`;
      const res = await fetch(url, { headers, mode: 'cors' });
      return handleResponse(res, url);
    },
    async getAdminData() {
      const url = `${base}/api/admin/data`;
      const res = await fetch(url, { headers, mode: 'cors' });
      return handleResponse(res, url);
    },
