const handleResponse = async (res: Response, url: string) => {
  if (!res.ok) {
    let errorData = {};
    try {
      errorData = await res.json();
    } catch (e) {
      errorData = { error: await res.text() || res.statusText };
    }
    throw new Error((errorData as any).error || `HTTP error! status: ${res.status}`);
  }
  return res.json();
};

